20: void SotwSubscriptionState::updateSubscriptionInterest(
21:     const absl::flat_hash_set<std::string>& cur_added,
22:     const absl::flat_hash_set<std::string>& cur_removed) {
23:   for (const auto& a : cur_added) {
24:     names_tracked_.insert(a);
25:   }
26:   for (const auto& r : cur_removed) {
27:     names_tracked_.erase(r);
28:   }
29:   if (!cur_added.empty() || !cur_removed.empty()) {
30:     update_pending_ = true;
31:   }
32: }
33: 
34: // Not having sent any requests yet counts as an "update pending" since you're supposed to resend
35: // the entirety of your interest at the start of a stream, even if nothing has changed.
36: bool SotwSubscriptionState::subscriptionUpdatePending() const {
37:   return update_pending_ || dynamicContextChanged();
38: }
39: 
40: void SotwSubscriptionState::markStreamFresh() {
41:   last_good_nonce_ = absl::nullopt;
42:   update_pending_ = true;
43:   clearDynamicContextChanged();
44: }
