24: LdsApiImpl::LdsApiImpl(const envoy::config::core::v3::ConfigSource& lds_config,
25:                        const xds::core::v3::ResourceLocator* lds_resources_locator,
26:                        Upstream::ClusterManager& cm, Init::Manager& init_manager,
27:                        Stats::Scope& scope, ListenerManager& lm,
28:                        ProtobufMessage::ValidationVisitor& validation_visitor)
29:     : Envoy::Config::SubscriptionBase<envoy::config::listener::v3::Listener>(validation_visitor,
30:                                                                              "name"),
31:       listener_manager_(lm), scope_(scope.createScope("listener_manager.lds.")), cm_(cm),
32:       init_target_("LDS", [this]() { subscription_->start({}); }) {
33:   const auto resource_name = getResourceName();
34:   if (lds_resources_locator == nullptr) {
35:     subscription_ = THROW_OR_RETURN_VALUE(cm.subscriptionFactory().subscriptionFromConfigSource(
36:                                               lds_config, Grpc::Common::typeUrl(resource_name),
37:                                               *scope_, *this, resource_decoder_, {}),
38:                                           Config::SubscriptionPtr);
39:   } else {
40:     subscription_ = THROW_OR_RETURN_VALUE(
41:         cm.subscriptionFactory().collectionSubscriptionFromUrl(
42:             *lds_resources_locator, lds_config, resource_name, *scope_, *this, resource_decoder_),
43:         Config::SubscriptionPtr);
44:   }
45:   init_manager.add(init_target_);
46: }
