48: absl::Status
49: LdsApiImpl::onConfigUpdate(const std::vector<Config::DecodedResourceRef>& added_resources,
50:                            const Protobuf::RepeatedPtrField<std::string>& removed_resources,
51:                            const std::string& system_version_info) {
52:   Config::ScopedResume maybe_resume_rds_sds;
53:   if (cm_.adsMux()) {
54:     const std::vector<std::string> paused_xds_types{
55:         Config::getTypeUrl<envoy::config::route::v3::RouteConfiguration>(),
56:         Config::getTypeUrl<envoy::config::route::v3::ScopedRouteConfiguration>(),
57:         Config::getTypeUrl<envoy::extensions::transport_sockets::tls::v3::Secret>()};
58:     maybe_resume_rds_sds = cm_.adsMux()->pause(paused_xds_types);
59:   }
60: 
61:   bool any_applied = false;
62:   listener_manager_.beginListenerUpdate();
63: 
64:   // We do all listener removals before adding the new listeners. This allows adding a new
65:   // listener with the same address as a listener that is to be removed. Do not change the order.
66:   for (const auto& removed_listener : removed_resources) {
67:     if (listener_manager_.removeListener(removed_listener)) {
68:       ENVOY_LOG(info, "lds: remove listener '{}'", removed_listener);
69:       any_applied = true;
70:     }
71:   }
72: 
73:   ListenerManager::FailureStates failure_state;
74:   absl::node_hash_set<std::string> listener_names;
75:   std::string message;
76: 
77:   for (const auto& resource : added_resources) {
78:     envoy::config::listener::v3::Listener listener;
79: 
80:     auto onError = [&](std::string error_message) {
81:       failure_state.push_back(std::make_unique<envoy::admin::v3::UpdateFailureState>());
82:       auto& state = failure_state.back();
83:       state->set_details(error_message);
84: #if defined(ENVOY_ENABLE_FULL_PROTOS)
85:       state->mutable_failed_configuration()->PackFrom(resource.get().resource());
86: #endif
87:       absl::StrAppend(&message, listener.name(), ": ", error_message, "\n");
88:     };
89: 
90:     TRY_ASSERT_MAIN_THREAD {
91:       listener =
92:           dynamic_cast<const envoy::config::listener::v3::Listener&>(resource.get().resource());
93:       if (!listener_names.insert(listener.name()).second) {
94:         // NOTE: at this point, the first of these duplicates has already been successfully
95:         // applied.
96:         onError(fmt::format("duplicate listener {} found", listener.name()));
97:         continue;
98:       }
99:       absl::StatusOr<bool> update_or_error =
100:           listener_manager_.addOrUpdateListener(listener, resource.get().version(), true);
