530:   for (const auto& api_state : api_state_) {
531:     for (auto watch : api_state.second->watches_) {
532:       watch->callbacks_.onConfigUpdateFailed(
533:           Envoy::Config::ConfigUpdateFailureReason::ConnectionFailure, nullptr);
534:     }
535:     if (!api_state.second->previously_fetched_data_) {
536:       // On the initialization of the gRPC mux, if connection to the xDS server fails, load the
537:       // persisted config, if available. The locally persisted config will be used until
538:       // connectivity is established with the xDS server.
539:       loadConfigFromDelegate(
